using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the MEAI chat client from OpenAI ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Instantiate tool backing services ---
var notebook = new Notebook();

// --- Register tools ---
IList<AITool> tools =
[
    AIFunctionFactory.Create(WebSearcher.SearchAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
];

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. When given a topic, follow these steps:
        1. Use the SearchAsync tool to find relevant information (perform 2-3 searches
           with varied queries to get broad coverage).
        2. Use the SaveNote tool to record key findings from each search.
        3. Use the GetNotes tool to review all your collected notes.
        4. Write a comprehensive, well-structured summary that synthesizes your findings.

        Always cite your sources with URLs. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An AI research assistant that searches the web and takes notes",
    tools: tools,
    loggerFactory: null,
    services: null);

// --- Get the research topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// --- Run the agent with streaming output ---
var session = await agent.CreateSessionAsync("research-session");
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic thoroughly: {topic}",
    session,
    runOptions))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();

// =====================================================================
// Tool implementations
// =====================================================================

/// <summary>Searches the web using DuckDuckGo and returns parsed results.</summary>
public static partial class WebSearcher
{
    private static readonly HttpClient s_http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
    };

    [Description("Search the web for information on a given query. Returns search result titles, URLs, and snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await s_http.GetStringAsync(url, cancellationToken);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
                return $"No results found for: {query}";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: {query}\n");
            foreach (var (title, link, snippet) in results.Take(5))
            {
                sb.AppendLine($"Title: {title}");
                sb.AppendLine($"URL: {link}");
                sb.AppendLine($"Snippet: {snippet}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    private static List<(string Title, string Url, string Snippet)> ParseSearchResults(string html)
    {
        var results = new List<(string, string, string)>();

        var resultBlocks = ResultBlockRegex().Matches(html);
        foreach (Match block in resultBlocks)
        {
            var linkMatch = LinkRegex().Match(block.Value);
            var snippetMatch = SnippetRegex().Match(block.Value);

            if (!linkMatch.Success)
                continue;

            var rawUrl = WebUtility.HtmlDecode(linkMatch.Groups[1].Value);
            var uddgMatch = UddgRegex().Match(rawUrl);
            var finalUrl = uddgMatch.Success
                ? WebUtility.UrlDecode(uddgMatch.Groups[1].Value)
